    switch flag
        case 0 
            [sys,x0,str,ts] = mdlInitializeSizes; 
        case 2 
            sys = mdlUpdates(t,x,u); 
        case 3 
            sys = mdlOutputs(t,x,u); 
        case {1,4,9} 
            sys = [];            
        otherwise 
            error(['unhandled flag = ',num2str(flag)]); 
